import{St as e,j as t,k as n}from"./C2wy_3lr.js";import"./CT0T0Gak.js";import"./cry5Dbjr.js";var r={title:`Video Highlights from the DREAMER Study Visit to Poland`,date:`21.01.2026`,categories:[`events`],published:!0},{title:i,date:a,categories:o,published:s}=r,c=t(`<p>We are pleased to share two short videos prepared by our Polish partner, capturing key moments from the DREAMER study visit hosted by Kozminski University in Warsaw on 27–31 October 2025.</p> <p>The videos offer a brief glimpse into the atmosphere of the visit, which brought together consortium partners for working sessions, expert master classes, and a site visit to the Warszawa Zachodnia railway station construction project. They reflect the collaborative spirit of DREAMER and the project’s focus on strengthening advanced project management capacities through international cooperation and shared learning.</p> <p>We sincerely thank our Polish partner for preparing these video highlights and invite you to watch them here:</p> <p><a href="https://youtu.be/IDAbIQDROQY" rel="nofollow">Video 1</a></p> <p><a href="https://youtube.com/shorts/DaMgNZ2jGlw" rel="nofollow">Video 2</a></p>`,1);function l(t){var r=c();e(8),n(t,r)}export{l as default,r as metadata};